def apply_config(client: KongAdminClient, config: Dict[str, Any]) -> Dict[str, Any]:
    results: Dict[str, Any] = {"services": [], "routes": [], "upstreams": [], "targets": []}

    for upstream in config.get("upstreams", []):
        upstream_payload = {k: v for k, v in upstream.items() if k != "targets"}
        upstream_result = client.ensure_upstream(upstream_payload)
        results["upstreams"].append(upstream_result)

        for target in upstream.get("targets", []):
            target_result = client.ensure_target(upstream["name"], target)
            results["targets"].append(target_result)

    for service in config.get("services", []):
        routes = service.pop("routes", [])
        service_result = client.ensure_service(service)
        results["services"].append(service_result)

        if service.get("host") in {None, ""} and service.get("upstream"):
            client.ensure_service_host_points_to_upstream(service["name"], service["upstream"])

        for route in routes:
            route_result = client.ensure_route(service["name"], route)
            results["routes"].append(route_result)

    return results


