def load_config_from_file(path: str) -> Dict[str, Any]:
    with open(path, "r", encoding="utf-8") as f:
        return json.load(f)


def main() -> int:
    admin_url = os.getenv("KONG_ADMIN_URL", DEFAULT_ADMIN_URL)
    config_path = os.getenv("KONG_CONFIG_FILE")

    if len(sys.argv) > 1:
        config_path = sys.argv[1]

    if config_path:
        config = load_config_from_file(config_path)
    else:
        config = sample_config()

    client = KongAdminClient(admin_url=admin_url)

    if not client.healthcheck():
        print(json.dumps({"error": f"Kong Admin API not reachable at {admin_url}"}))
        return 1

    try:
        result = apply_config(client, config)
        print(json.dumps({"status": "success", "admin_url": admin_url, "result": result}, indent=2))
        return 0
    except Exception as e:
        print(json.dumps({"status": "error", "message": str(e)}))
        return 2


if __name__ == "__main__":
    sys.exit(main())